LIBWK2GTKPDF_1.0 {
    global:
        # --- C Linkage & Globals ---
        PDF_Free*;
        wk2gtkpdf_version;
        LOG_LEVEL;
        LOG_IGNORE;
        wkJlog;

        # New Python-friendly C Bridge entry points:
        wk2gtk_printer_create;
        wk2gtk_printer_set_param;
        wk2gtk_printer_make_pdf;
        wk2gtk_printer_destroy;

        # --- C++ Mangled Prefixes ---
        # Note: K for const (obviously!)
        # The Printer & Tree classes
        _ZN5phtml10PDFprinter*;
        _ZNK5phtml10PDFprinter*;

        _ZN5phtml9html_tree*;
        _ZNK5phtml9html_tree*;

        _ZN5phtml12encode_image*;
        _ZNK5phtml12encode_image*;

        _ZN5phtml13process_nodes*;

        # The Logger (iclog::logstream)
        # This catches C1/C2 (ctors), D1/D2 (dtors), flush, and ALL operator<<
        _ZN5iclog9logstream*;

        # The Logger Helpers (iclog::endl and standalone operator<<)
        _ZN5iclog4endl*;
        _ZN5iclogls*;

        # GTK Init
        _ZN5icGTK4init*;

    local:
        # This is what kills those 7 "streambuf_internal" symbols
        # because they start with _ZN5iclog18streambuf_internal
        *;
};
